def word_ladder_len(begin, end, words):
    """
    Returns the length of the shortest word ladder from begin to end,
    where each step changes exactly one letter and all intermediate words
    are in the given list. Returns 0 if no such ladder exists.
    """
    words_set = set(words)
    if end not in words_set:
        return 0
    if begin == end:
        return 1

    from collections import deque
    queue = deque()
    queue.append((begin, 1))
    visited = {begin}

    while queue:
        current, dist = queue.popleft()
        for i in range(len(current)):
            for c in 'abcdefghijklmnopqrstuvwxyz':
                if c == current[i]:
                    continue
                neighbor = current[:i] + c + current[i+1:]
                if neighbor in words_set and neighbor not in visited:
                    if neighbor == end:
                        return dist + 1
                    visited.add(neighbor)
                    queue.append((neighbor, dist + 1))

    return 0
